select i.in_id, i.ent_code, i.in_no, i.in_time, i.warehouse_id, w.warehouse_name, i.arrival_no, i.purchaser,
       i.in_user, i.status, i.audit_by, i.audit_time, i.audit_remark, i.total_qty, i.total_amount,
       i.stock_effect_status, i.remark, i.create_time, i.update_time
from t_material_in_order i
left join t_material_warehouse w on w.warehouse_id = i.warehouse_id



            and i.ent_code = #{entCode}



                and i.ent_code in

                    #{entCode}





        and i.warehouse_id = #{warehouseId}


        and i.in_no like concat('%', #{orderNo}, '%')


        and i.status = #{status}


        and i.in_time between #{startTime} and #{endTime}


        and exists (select 1 from t_material_in_order_item ii where ii.in_id = i.in_id and ii.material_name like concat('%', #{materialName}, '%'))


order by i.in_time desc, i.in_id desc

